function DiceRandom() {
  const STARARR = [];
  let nums = 0;
  let STAR = 0;
  let MAXSTAR = 0;
  while (STAR == 0) {
    for (let count = 0; count < 6; count++) {
      STARARR[count] = Math.trunc(Math.random() * 6 + 1);
      if (MAXSTAR == 2 && STARARR[count] == 6) {
        while (STARARR[count] == 6) {
          STARARR[count] = Math.trunc(Math.random() * 6 + 1);
        }
      }
      if (STARARR[count] == 6) {
        MAXSTAR++;
      }
      STAR += count;
    }
    STARARR.forEach((value) => {
      nums += value;
    });
    if (nums > 24) {
      DiceRandom();
    } else {
      // console.log(nums, STARARR);
      return {
        num: nums,
        arrs: STARARR,
      };
    }
  }
}
function baseDice(Star) {
  let TRY = [];
  let DICE = 0;
  for (let count = 0; count < Star; count++) {
    TRY[count] = getRandomArbitrary(Star * 8, Star * 25);
  }
  //console.log(DICE, TRY);
  DICE = Math.min(
    TRY[getRandomArbitrary(0, Star - 1)] + getRandomArbitrary(-3, 4),
    145
  );

  if (Star == 1) {
    DICE = getRandomArbitrary(18, 26);
  }
  //  console.log(DICE, TRY);
  return DICE;
}
function getRandomArbitrary(min, max) {
  return Math.trunc(Math.random() * (max - min) + min);
}
function baseCorrection(age, str) {
  let num = getRandomArbitrary(1, 3);
  let num1 = getRandomArbitrary(0, Math.trunc(age / 4));
  // console.log(num1, num);
  if (age < 24) {
    if (str == "str" || str == "con" || str == "dex") {
      return num + num1;
    } else if (str == "int" || str == "pow" || str == "cha") {
      return 0 - num - num1;
    }
  } else if (age > 32) {
    if (str == "str" || str == "con" || str == "dex") {
      return 0 - num - num1;
    } else if (str == "int" || str == "pow" || str == "cha") {
      return num + num1;
    }
  }
  return 0;
}
function Evaluation(num) {
  if (801 <= num && num <= 999) {
    return "EX+";
  } else if (501 <= num && num <= 800) {
    return "EX";
  } else if (251 <= num && num <= 500) {
    return "SSS";
  } else if (221 <= num && num <= 250) {
    return "S+";
  } else if (181 <= num && num <= 220) {
    return "S";
  } else if (175 <= num && num <= 180) {
    return "S-";
  } else if (161 <= num && num <= 175) {
    return "A+";
  } else if (121 <= num && num <= 160) {
    return "A";
  } else if (119 <= num && num <= 120) {
    return "A-";
  } else if (100 <= num && num <= 118) {
    return "B+";
  } else if (81 <= num && num <= 99) {
    return "B";
  } else if (79 <= num && num <= 80) {
    return "B-";
  } else if (61 <= num && num <= 78) {
    return "C";
  } else if (59 <= num && num <= 60) {
    return "C-";
  } else if (41 <= num && num <= 58) {
    return "D";
  } else if (39 <= num && num <= 40) {
    return "D-";
  } else if (20 <= num && num <= 38) {
    return "E";
  } else if (1 <= num && num <= 19) {
    return "F";
  }
}
