  return string;
}
function skillstr(arr) {
  let string = "";
  arr.forEach((value) => {
    console.log(value.str);
    if (value.str == "") {
      string += `【${value.name}】<br>`;
    } else {
      string += `【${value.name}】:${value.str}<br>`;
    }
  });
  return string;
}
