function CombatPoint(arr, str) {
  let { intvalue, strvalue, dexvalue, convalue, powvalue, spirit } = arr;
  console.log(str);
  const BP =
    strvalue + dexvalue + Math.trunc(convalue / 2) + Math.trunc(powvalue / 2);
  const VALUE = intvalue + powvalue;
  if (str == "战斗力") {
    return BP;
  } else if (str == "异能战斗力") {
    const num = VALUE + Math.trunc((Math.min(spirit, 1) * 5 * BP) / 100);
    //console.log(num, VALUE, spirit, BP);
    return num;
  }
}
